B.pH=s(["text","multiline","number","phone","datetime","emailAddress","url","visiblePassword","name","address","none","webSearch","twitter"],t.s)
B.pI=s(["Jan","Feb","Mar","Apr","May","Jun","Jul","Aug","Sep","Oct","Nov","Dec"],t.s)
B.Nb=s(["J\u2019ai sacrifi\xe9 ma main pour encha\xeener un loup.","Je suis le dieu manchot de la justice et de la guerre h\xe9ro\xefque.","Mon nom est synonyme de courage."],t.s)
B.Rw=new A.cv("TYR",B.Nb)
B.O4=s(["J\u2019ai \xe9chang\xe9 un \u0153il contre la sagesse.","Mes deux corbeaux parcourent le monde pour m\u2019informer.","Je suis le P\xe8re de Tout, r\xe9gnant depuis Asgard."],t.s)
B.Rq=new A.cv("ODIN",B.O4)
B.Oc=s(["Mon char est tir\xe9 par des boucs.","Je suis le protecteur de Midgard et le fils d\u2019Odin.","Le tonnerre gronde quand je lance mon marteau."],t.s)
B.Rs=new A.cv("THOR",B.Oc)
B.Mr=s(["Je suis le p\xe8re de monstres et le ma\xeetre de la tromperie.","Mon sang s\u2019est m\xeal\xe9 \xe0 celui d\u2019Odin.","Je change de forme comme je change d\u2019avis."],t.s)
B.Rr=new A.cv("LOKI",B.Mr)
B.NU=s(["Je pleure des larmes d\u2019or pour mon \xe9poux parti.","Je r\xe8gne sur le F\xf3lkvangr et re\xe7ois la moiti\xe9 des guerriers morts.","Mon collier, Br\xedsingamen, est le plus beau des tr\xe9sors."],t.s)
B.Rv=new A.cv("FREYA",B.NU)
B.MT=s(["Je connais le destin de tous, mais je garde le silence.","Je suis l\u2019\xe9pouse d\u2019Odin et la reine d\u2019Asgard.","J\u2019ai pleur\xe9 la mort de mon fils lumineux."],t.s)
B.Rl=new A.cv("FRIGG",B.MT)
B.MO=s(["Ma m\xe2choire, une fois ouverte, touche le ciel et la terre.","Les dieux m\u2019ont encha\xeen\xe9 par la ruse avec un ruban de soie.","Je d\xe9vorerai Odin lors de la derni\xe8re bataille."],t.s)
B.Rn=new A.cv("FENRIR",B.MO)
B.M1=s(["Je suis la forteresse des dieux Ases.","Mes murs ont \xe9t\xe9 construits par un g\xe9ant et son cheval.","Le pont arc-en-ciel m\xe8ne \xe0 mes portes."],t.s)
B.Rh=new A.cv("ASGARD",B.M1)
B.NK=s(["Chaque matin, je pars pour ne revenir qu\u2019au soir.","Je suis la Pens\xe9e qui vole pour le P\xe8re de Tout.","Mon fr\xe8re est la M\xe9moire."],t.s)
B.RA=new A.cv("HUGINN",B.NK)
B.NX=s(["Je suis un pont de feu gard\xe9 par un dieu vigilant.","Mes trois couleurs relient le monde des hommes \xe0 celui des dieux.","Je me briserai sous le poids des g\xe9ants \xe0 la fin des temps."],t.s)
B.Rx=new A.cv("BIFROST",B.NX)
B.NG=s(["Je reviens toujours \xe0 la main de mon ma\xeetre.","Mon vol dans le ciel est le son du tonnerre.","Je suis le broyeur, terreur des g\xe9ants."],t.s)
B.Ro=new A.cv("MJOLNIR",B.NG)
B.Oa=s(["Je suis le royaume des mortels.","Un serpent g\xe9ant entoure mes c\xf4tes.","Je suis prot\xe9g\xe9 par le fils d\u2019Odin au marteau."],t.s)
B.Rf=new A.cv("MIDGARD",B.Oa)
B.NH=s(["Mon toit est couvert de boucliers dor\xe9s.","Ici, les guerriers d\u2019\xe9lite festoient et combattent chaque jour.","Je suis le grand hall d\u2019Odin pour les morts valeureux."],t.s)
B.Rk=new A.cv("VALHALLA",B.NH)
B.Mm=s(["Je suis la lance qui ne manque jamais sa cible.","Mon propri\xe9taire s\u2019est pendu \xe0 un arbre avec moi dans le flanc.","Un serment pr\xeat\xe9 sur ma pointe est inviolable."],t.s)
B.Ry=new A.cv("GUNGNIR",B.Mm)
B.Mj=s(["Je suis le cr\xe9puscule des dieux.","Le soleil deviendra noir et la terre sombrera dans la mer.","Je suis une fin, mais aussi un nouveau commencement."],t.s)
B.Rz=new A.cv("RAGNAROK",B.Mj)
